-- part of a query repo
-- query name: Balancer Liquidity Mining Data
-- query link: https://dune.com/queries/83381


DROP TABLE IF EXISTS dune_user_generated.balancer_liquidity_mining;

CREATE TABLE dune_user_generated.balancer_liquidity_mining (
    day timestamptz,
    chain_id text,
    pool_id bytea,
    amount numeric,
    usd_amount numeric
);

WITH bal_price AS (
        SELECT date_trunc('week', minute) AS week, AVG(price) AS price
        FROM prices.usd
        WHERE minute > '2021-04-20'
        AND contract_address = '\xba100000625a3754423978a60c9317c58a424e3d'
        GROUP BY 1
    ),
    
    calendar AS (
        SELECT generate_series('2020/06/01'::timestamptz, date_trunc('week', now() + '1 week'), '1 day'::interval) AS day
    ),

    weeks_calendar AS (
        SELECT generate_series('2020/06/01'::timestamptz, date_trunc('week', now() + '1 week'), '1 week'::interval) AS week_timestamp
    ),

    weeks_map AS (
        SELECT week_timestamp, ROW_NUMBER() OVER (ORDER BY 1) AS week_number
        FROM weeks_calendar
    ),

