in_id": 42161, "pool_id": "0xc61ff48f94d801c1ceface0289085197b5ec44f000020000000000000000004d", "token_address": "0x040d1edc9569d4bab2d15287dc5a4f10f56a56b8", "amount": 300}, {"week": "week_99", "chain_id": 42161, "pool_id": "0x0510ccf9eb3ab03c1508d3b9769e8ee2cfd6fdcf00000000000000000000005d", "token_address": "0x040d1edc9569d4bab2d15287dc5a4f10f56a56b8", "amount": 400}, {"week": "week_99", "chain_id": 42161, "pool_id": "0x5a5884fc31948d59df2aeccca143de900d49e1a300000000000000000000006f", "token_address": "0x040d1edc9569d4bab2d15287dc5a4f10f56a56b8", "amount": 100}]}
        ')
        ) a (denorm_json)
    ),

    records AS (
        SELECT json_array_elements(denorm_json->'data') AS record
        FROM denorm_json
    ),
    
    rewards_raw AS (
        SELECT
            (record->>'week') AS week,
            (record->>'chain_id')::decimal AS chain_id,
            REPLACE((record->>'pool_id'),'0x','\x')::bytea AS pool_id,
            REPLACE((record->>'token_address'),'0x','\x')::bytea AS token_address,
            (record->>'amount') AS amount
        FROM records
    ),
    
    rewards AS (
        SELECT 
            week_timestamp AS day, 
            LEAD(week_timestamp, 1, week_timestamp + '1 week') OVER (PARTITION BY chain_id, pool_id ORDER BY week_timestamp) AS day_of_next_change,
            chain_id,
            pool_id, 
            amount
        FROM rewards_raw r
        JOIN weeks_map w ON w.week_number = SUBSTRING(r.week, 6)::int
        WHERE token_address = '\xba100000625a3754423978a60c9317c58a424e3d'
    ),
    
    last_week AS (
        SELECT day + '7 days' AS last_day
        FROM rewards
        ORDER BY 1 DESC
        LIMIT 1
    ),
    
    rows AS (
        INSERT INTO dune_user_generated.balancer_liquidity_mining
        SELECT 
            c.day, 
            chain_id,
            pool_id,
            amount::float/7 AS amount,
            price*amount::float/7 AS usd_amount
        FROM calendar c
        LEFT JOIN rewards b ON b.day <= c.day AND c.day < b.day_of_next_change
        JOIN bal_price p ON p.week = date_trunc('week', c.day)
        WHERE amount IS NOT NULL
        RETURNING 1
    )

SELECT last_day::date, COUNT(*)
FROM rows
JOIN last_week ON 1=1
GROUP BY 1